// Map Google Form question titles → short field names used in code
const HEADER_MAP = {
  "timestamp":                      "timestamp",
  "email address":                  "email",
  "site name":                      "site_name",
  "location name":                  "location_name",
  "latitude":                       "lat",
  "longitude":                      "lon",
  "local time":                     "local_time",
  "observation date":               "obs_date",
  "sky brightness meter model":     "sqm_model",
  "meter serial":                   "sqm_serial",
  "meter version":                  "sqm_version",
  "reading 1":                      "r1",
  "reading 2":                      "r2",
  "reading 3":                      "r3",
  "reading 4":                      "r4",
  "reading 5":                      "r5",
  "cloud cover %":                  "cloud_pct",
  "moon visible %":                 "moon_pct",
  "temperature °c":                 "temp_c",
  "notes":                          "notes",
  "session id":                     "session_id",
};

function normaliseHeader(h) {
  const lower = h.trim().toLowerCase();
  return HEADER_MAP[lower] || lower.replace(/\s+/g,"_").replace(/[^a-z0-9_]/g,"");
}

function parseCSV(text) {
  const lines = text.trim().split("\n");
  if (lines.length < 2) return [];
  const headers = lines[0].split(",").map(h => normaliseHeader(h.replace(/^"|"$/g,"")));
  return lines.slice(1).map(line => {
    const fields = [];
    let cur = "", inQ = false;
    for (let i = 0; i < line.length; i++) {
      const ch = line[i];
      if (ch === '"') { inQ = !inQ; }
      else if (ch === "," && !inQ) { fields.push(cur.trim()); cur = ""; }
      else { cur += ch; }
    }
    fields.push(cur.trim());
    const row = {};
    headers.forEach((h, i) => { row[h] = (fields[i] ?? "").replace(/^"|"$/g, ""); });
    return row;
  }).filter(row => Object.values(row).some(v => v !== ""));
}

function sqmToNum(v) { const n = parseFloat(v); return isNaN(n) ? null : n; }

function sqmMedian(arr) {
  const s = [...arr].sort((a,b)=>a-b);
  const m = Math.floor(s.length/2);
  return s.length % 2 === 0 ? (s[m-1]+s[m])/2 : s[m];
}

function sqmFmtDate(ts) {
  if (!ts) return "—";
  const d = new Date(ts);
  if (isNaN(d)) return ts;
  return d.toLocaleDateString("en-CA", { year:"numeric", month:"short", day:"numeric" });
}

// Bortle class from SQM median (standard conversion)
function sqmToBortle(sqm) {
  if (sqm === null) return null;
  if (sqm >= 22.0) return 1;
  if (sqm >= 21.9) return 2;
  if (sqm >= 21.5) return 3;
  if (sqm >= 20.9) return 4;
  if (sqm >= 20.4) return 5;
  if (sqm >= 19.5) return 6;
  if (sqm >= 18.5) return 7;
  return 8;
}

function bortleColor(b) {
  if (!b) return "#888";
  if (b <= 2) return "#5dcc80";
  if (b <= 3) return "#84cc16";
  if (b <= 4) return "#a3c940";
  if (b <= 5) return "#d9a83a";
  if (b <= 6) return "#d97c3a";
  return "#b06060";
}

function sqmQuality(avg) {
  if (avg === null) return { label:"—", color:"#6b7280" };
  if (avg >= 21.5)  return { label:"Excellent", color:"#5dcc80" };
  if (avg >= 21.0)  return { label:"Good",      color:"#84cc16" };
  if (avg >= 20.0)  return { label:"Fair",       color:"#d9a83a" };
  return                   { label:"Poor",       color:"#b06060" };
}

function isRecent(ts) {
  if (!ts) return false;
  const d = new Date(ts);
  if (isNaN(d)) return false;
  return (Date.now() - d.getTime()) < 365 * 24 * 3600 * 1000;
}

// Haversine distance in metres between two lat/lon points
function haversineM(lat1, lon1, lat2, lon2) {
  const R = 6371000, dLat=(lat2-lat1)*DEG, dLon=(lon2-lon1)*DEG;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*DEG)*Math.cos(lat2*DEG)*Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function SQMTooltip({ active, payload, label }) {
  if (!active || !payload?.length) return null;
  const val = payload[0]?.value;
  const q = sqmQuality(val);
  return (
    <div style={{background:"#0d1827",border:"1px solid rgba(100,140,255,0.2)",borderRadius:8,padding:"10px 14px",fontSize:12,lineHeight:1.6}}>
      <div style={{color:"rgba(245,230,160,0.65)",marginBottom:3}}>{label}</div>
      <div style={{fontWeight:600,fontSize:15,color:q.color}}>{val?.toFixed(2)}</div>
      <div style={{fontSize:11,color:q.color}}>{q.label}</div>
    </div>
  );
}

